                envnum_f="optional",
                hdgrade_f="optional",
                mined_f="optional",
                density_f="optional",
                cutoff_p="required",
                hdgrade_p="required",
                defgrade_p=0,
                defvalue_p=0,
                density_p=1,
                maxwaste_p="required",
                maxore_p="required",
                pdwvalue_p="required",
                pdwgrade_p="required",
