                xvstats_o="optional",
                sampout_o="optional",
                x_f="optional",
                y_f="optional",
                z_f="optional",
                zone1_f_f="optional",
                zone2_f_f="optional",
                key_f="optional",
                length_f_f="optional",
                dens_f_f="optional",
                sminfac_p=0.0001,
